--------------------------
/*-- 1. UPC_SECTION --*/
--------------------------
CREATE SEQUENCE CASV3_SEQ_UPC_SECTION_AUD INCREMENT BY 1 START WITH 1 MAXVALUE 9999999999999999999999999999999999999 MINVALUE 1 NOCACHE;

CREATE TABLE CASV3_T_UPC_SECTION_AUD AS
SELECT
    CAST(NULL AS NUMBER) AS ID,
    t.*
FROM T_UPC_SECTION t
WHERE 1 = 0;

CREATE TABLE CASV3_T_UPC_SECTION_TEMP AS
SELECT *
FROM T_UPC_SECTION
WHERE 1 = 0;

INSERT INTO CASV3_T_UPC_SECTION_AUD
SELECT
    CASV3_SEQ_UPC_SECTION_AUD.NEXTVAL AS ID,
    t.*
FROM T_UPC_SECTION t;


ALTER TABLE CASV3_T_UPC_SECTION_AUD
ADD CONSTRAINT PK_CASV3_UPC_SECTION_AUD
PRIMARY KEY (ID);

DELETE FROM T_UPC_SECTION s
WHERE (s.approve_status <> 'APPROVED'
   OR s.status <> 'ACT')
AND NOT EXISTS (
    SELECT 1
    FROM T_FP_UPC_SECTION_DATA d
    WHERE d.UPC_SECTION_ID = s.UPC_SECTION_ID
)
AND NOT EXISTS (
    SELECT 1
    FROM T_UPC_TEMPLATE_DATA t
    WHERE t.UPC_SECTION_ID = s.UPC_SECTION_ID
);

