/*-- 1. CREDIT FACILITY TEMPLATE --*/
---------------------------------------
---1----
CREATE SEQUENCE CASV3_SEQ_CREDIT_FACILITY_TEMPLATE_AUD INCREMENT BY 1 START WITH 1 MAXVALUE 9999999999999999999999999999999999999 MINVALUE 1 NOCACHE;

---2----
CREATE TABLE CASV3_T_CREDIT_FACILITY_TEMPLATE_AUD AS
SELECT
    CAST(NULL AS NUMBER) AS ID,
    t.*
FROM T_CREDIT_FACILITY_TEMPLATE t
WHERE 1 = 0;

CREATE TABLE CASV3_T_CREDIT_FACILITY_TEMPLATE_TEMP AS
SELECT *
FROM T_CREDIT_FACILITY_TEMPLATE
WHERE 1 = 0;

---3----
INSERT INTO CASV3_T_CREDIT_FACILITY_TEMPLATE_AUD
SELECT
    CASV3_SEQ_CREDIT_FACILITY_TEMPLATE_AUD.NEXTVAL,
    t.*
FROM T_CREDIT_FACILITY_TEMPLATE t;

---4----
ALTER TABLE CASV3_T_CREDIT_FACILITY_TEMPLATE_AUD
ADD CONSTRAINT PK_CASV3_FAC_TEMPLATE_AUD
PRIMARY KEY (ID);

---5----
DELETE FROM T_CREDIT_FACILITY_TEMPLATE s
WHERE (s.approve_status <> 'APPROVED'
   OR s.status <> 'ACT')

AND NOT EXISTS (
    SELECT 1
    FROM T_CFT_VITAL_INFO d
    WHERE D.CREDIT_FACILITY_TEMPLATE_ID = s.CREDIT_FACILITY_TEMPLATE_ID
)

AND NOT EXISTS (
    SELECT 1
    FROM T_CFT_INTEREST_RATE t
    WHERE t.CREDIT_FACILITY_TEMPLATE_ID = s.CREDIT_FACILITY_TEMPLATE_ID
)

AND NOT EXISTS (
    SELECT 1
    FROM T_FACILITY d
    WHERE D.CREDIT_FACILITY_TEMPLATE_ID = s.CREDIT_FACILITY_TEMPLATE_ID
)

AND NOT EXISTS (
    SELECT 1
    FROM T_CFT_SUPPORTING_DOC d
    WHERE D.CREDIT_FACILITY_TEMPLATE_ID = s.CREDIT_FACILITY_TEMPLATE_ID
)

AND NOT EXISTS (
    SELECT 1
    FROM T_CFT_OTHER_FACILITY_INFO d
    WHERE D.CREDIT_FACILITY_TEMPLATE_ID = s.CREDIT_FACILITY_TEMPLATE_ID
)

AND NOT EXISTS (
    SELECT 1
    FROM T_AF_FACILITY d
    WHERE D.CREDIT_FACILITY_TEMPLATE_ID = s.CREDIT_FACILITY_TEMPLATE_ID
);


