ADD (
    ACTION_MSG  VARCHAR2(500),
    ACTION_BY   VARCHAR2(100),
    ACTION_DATE DATE
);

---5----
DELETE FROM T_UPC_TEMPLATE_DATA d
WHERE EXISTS (
    SELECT 1
    FROM T_UPC_TEMPLATE t
    WHERE t.UPC_TEMPLATE_ID = d.UPC_TEMPLATE_ID
      AND (t.APPROVE_STATUS <> 'APPROVED'
           OR t.STATUS <> 'ACT')
);

DELETE FROM T_UPC_TEMPLATE t
WHERE t.APPROVE_STATUS <> 'APPROVED'
   OR t.STATUS <> 'ACT';


